+func findAgentByBeadsID(agents []AgentAPIResponse, beadsID string) (AgentAPIResponse, bool) {
+    for _, agent := range agents {
+        if agent.BeadsID == beadsID {
+            return agent, true
+        }
+    }
+    return AgentAPIResponse{}, false
+}
